def calculate_decay_rate(data):
    # Placeholder function for decay rate calculation
    return {key: len(value) / 100 for key, value in data.items()}

def prioritize_data(data, decay_rates):
    priority_queue = []
    for key, value in data.items():
        priority = -decay_rates[key] * len(value)
        heapq.heappush(priority_queue, (priority, key, value))
    return priority_queue

def compress_memory(data, max_layers=3):
    decay_rates = calculate_decay_rate(data)
    priority_queue = prioritize_data(data, decay_rates)
    compressed_data = defaultdict(list)

    for _ in range(max_layers):
        if not priority_queue:
            break
        _, key, value = heapq.heappop(priority_queue)
        compressed_data[key] = value

    return dict(compressed_data)

