from datetime import datetime, timedelta

class RateLimiter:
    def __init__(self, max_requests=100, time_window=timedelta(hours=1)):
        self.max_requests = max_requests
        self.time_window = time_window
        self.request_log = {}

    def is_allowed(self, user_id):
        now = datetime.now()
        user_requests = [req for req in self.request_log.get(user_id, []) if (now - req).total_seconds() <= self.time_window.total_seconds()]

        if len(user_requests) >= self.max_requests:
            return False
        else:
            self.request_log.setdefault(user_id, []).append(now)
            return True

