class AdaptiveWeightedPrioritization:
    def __init__(self, objectives, initial_weights):
        self.objectives = objectives
        self.weights = {obj: weight for obj, weight in zip(objectives, initial_weights)}

    def prioritize(self, tasks):
        weighted_scores = {task: sum(self.weights[obj] * task.get_metric(obj) for obj in self.objectives) for task in tasks}
        sorted_tasks = sorted(tasks, key=lambda x: weighted_scores[x], reverse=True)
        return sorted_tasks

    def update_weights(self, feedback):
        for task, score in zip(feedback['tasks'], feedback['scores']):
            for obj in self.objectives:
                self.weights[obj] += score * task.get_metric(obj) / len(self.objectives)

